INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 122601, 105, 1.5, 0.029, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 1, 0, 0, 101, 160, 1, 110, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 122401, 111, 2.5, 0.014, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 0, 0, 1, 102, 120, 2, 105, 2);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 122501, 105, 2.5, 0.017, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 0, 1, 0, 103, 350, 3, 110, 3);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 107501, 105, 1.5, 0.016, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 0, 0, 1, 104, 130, 4, 110, 4);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 107601, 105, 2.5, 0.014, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 1, 0, 0, 105, 160, 5, 110, 5);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 107801, 103, 3.5, 0.029, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 0, 1, 0, 106, 255, 6, 120, 6);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 110601, 103, 3.5, 0.013, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 1, 0, 0, 107, 160, 7, 120, 7);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 110401, 103, 2.5, 0.014, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 0, 1, 0, 108, 350, 8, 110, 8);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 110501, 100, 1.5, 0.012, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 0, 0, 1, 109, 130, 9, 105, 9);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 115701, 103, 2.5, 0.014, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 1, 0, 0, 110, 200, 10, 105, 10);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 113601, 103, 2.5, 0.071, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 0, 1, 0, 111, 350, 11, 105, 11);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 107901, 103, 1.5, 0.014, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 0, 0, 1, 112, 130, 12, 120, 12);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 108001, 105, 1.5, 0.022, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 1, 0, 0, 113, 200, 13, 110, 13);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 110301, 108, 2.5, 0.031, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 1, 0, 0, 114, 160, 14, 110, 14);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 107701, 105, 0.5, 0.036, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 0, 0, 1, 115, 130, 15, 110, 15);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 113101, 95, 3.5, 0.048, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 0, 1, 0, 116, 350, 16, 110, 16);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 113301, 105, 1.5, 0.043, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 0, 0, 1, 117, 130, 17, 105, 17);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 113201, 95, 1.5, 0.018, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 0, 0, 1, 118, 130, 18, 105, 18);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 117001, 108, 2.5, 0.021, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 1, 0, 0, 119, 160, 19, 110, 19);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 113501, 105, 2.5, 0.036, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 0, 1, 0, 120, 255, 20, 110, 20);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 113401, 105, 2.5, 0.02, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 0, 1, 0, 121, 350, 21, 105, 21);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 110101, 105, 2.5, 0.018, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 0, 0, 1, 122, 130, 22, 110, 22);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 110001, 111, 3.5, 0.03, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 1, 0, 0, 123, 160, 23, 105, 23);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 117201, 103, 1.5, 0.027, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 0, 0, 1, 124, 130, 24, 110, 24);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 117301, 108, 3.5, 0.02, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 1, 0, 0, 125, 160, 25, 105, 25);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 117401, 105, 2.5, 0.04, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 0, 1, 0, 126, 350, 26, 110, 26);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 117101, 105, 3.5, 0.009, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 0, 1, 0, 127, 350, 27, 110, 27);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (1, 122901, 105, 3.5, 0.022, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 0, 1, 0, 128, 255, 28, 120, 28);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (3, 122801, 105, 2.5, 0.028, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 0, 0, 1, 129, 130, 29, 110, 29);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (2, 122701, 108, 3.5, 0.023, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 1, 0, 0, 130, 130, 30, 105, 30);
